// MARK: - Keychain Manager

final class KeychainManager {
    
    static let shared = KeychainManager()
    
    private let serviceName = "com.app.datasecurity"
    
    private init() {}
    
    func save(data: Data, forKey key: String) throws {
        // Delete existing item first
        let deleteQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(deleteQuery as CFDictionary)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw DataSecurityError.keychainSaveFailed(status: status)
        }
    }
    
    func read(forKey key: String) throws -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecItemNotFound {
            return nil
        }
        
        guard status == errSecSuccess else {
            throw DataSecurityError.keychainReadFailed(status: status)
        }
        
        return result as? Data
    }
    
    func delete(forKey key: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw DataSecurityError.keychainDeleteFailed(status: status)
        }
    }
}

// MARK: - AES Crypto Engine

final class AESCryptoEngine {
    
    private let keySize = kCCKeySizeAES256
    private let blockSize = kCCBlockSizeAES128
    private let algorithm = CCAlgorithm(kCCAlgorithmAES)
    private let options = CCOptions(kCCOptionPKCS7Padding)
    
    static let shared = AESCryptoEngine()
    
    private init() {}
    
    // MARK: - Key Management (Secure - stored in Keychain)
    
    private let encryptionKeyKeychainIdentifier = "com.app.datasecurity.aes256.masterkey"
    
    /// Retrieves or generates the AES-256 encryption key from the Keychain.
    /// The key is never exposed in source code or the app binary.
    func getOrCreateEncryptionKey() throws -> Data {
        if let existingKey = try KeychainManager.shared.read(forKey: encryptionKeyKeychainIdentifier) {
            return existingKey
        }
        
        let newKey = try generateRandomKey()
        try KeychainManager.shared.save(data: newKey, forKey: encryptionKeyKeychainIdentifier)
        return newKey
    }
    
    private func generateRandomKey() throws -> Data {
        var keyData = Data(count: keySize)
        let result = keyData.withUnsafeMutableBytes { buffer in
            SecRandomCopyBytes(kSecRandomDefault, keySize, buffer.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        return keyData
    }
    
    private func generateRandomIV() throws -> Data {
        var ivData = Data(count: blockSize)
        let result = ivData.withUnsafeMutableBytes { buffer in
            SecRandomCopyBytes(kSecRandomDefault, blockSize, buffer.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        return ivData
    }
    
    // MARK: - Encryption
    
    func encrypt(data: Data) throws -> Data {
        let key = try getOrCreateEncryptionKey()
        let iv = try generateRandomIV()
        
        let bufferSize = data.count + blockSize
        var encryptedData = Data(count: bufferSize)
        var numBytesEncrypted: size_t = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                data.withUnsafeBytes { dataBytes in
                    encryptedData.withUnsafeMutableBytes { encryptedBytes in
                        CCCrypt(
                            CCOperation(kCCEncrypt),
                            algorithm,
                            options,
                            keyBytes.baseAddress!,
                            keySize,
                            ivBytes.baseAddress!,
                            dataBytes.baseAddress!,
                            data.count,
                            encryptedBytes.baseAddress!,
                            bufferSize,
                            &numBytesEncrypted
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.encryptionFailed(status: status)
        }
        
        encryptedData.removeSubrange(numBytesEncrypted..<encryptedData.count)
        
        // Prepend IV to encrypted data so we can use it for decryption
        var result = iv
        result.append(encryptedData)
        return result
    }
    
    // MARK: - Decryption
    
    func decrypt(data: Data) throws -> Data {
        let key = try getOrCreateEncryptionKey()
        
        guard data.count > blockSize else {
            throw DataSecurityError.invalidData
        }
        
        let iv = data.prefix(blockSize)
        let encryptedData = data.suffix(from: blockSize)
        
        let bufferSize = encryptedData.count + blockSize
        var decryptedData = Data(count: bufferSize)
        var numBytesDecrypted: size_t = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                encryptedData.withUnsafeBytes { encryptedBytes in
                    decryptedData.withUnsafeMutableBytes { decryptedBytes in
                        CCCrypt(
                            CCOperation(kCCDecrypt),
                            algorithm,
                            options,
                            keyBytes.baseAddress!,
                            keySize,
                            ivBytes.baseAddress!,
                            encryptedBytes.baseAddress!,
                            encryptedData.count,
                            decryptedBytes.baseAddress!,
                            bufferSize,
                            &numBytesDecrypted
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.decryptionFailed(status: status)
        }
        
        decryptedData.removeSubrange(numBytesDecrypted..<decryptedData.count)
        return decryptedData
    }
    
    // MARK: - String Convenience
    
    func encrypt(string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw DataSecurityError.encodingFailed
        }
        return try encrypt(data: data)
    }
    
    func decryptToString(data: Data) throws -> String {
        let decryptedData = try decrypt(data: data)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw DataSecurityError.decodingFailed
        }
        return string
    }
}

// MARK: - Secure Data Store

final class SecureDataStore {
    
    static let shared = SecureDataStore()
    
    private let cryptoEngine = AESCryptoEngine.shared
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()
    private let fileManager = FileManager.default
    
    private lazy var secureDirectoryURL: URL = {
        let documentsURL = fileManager.urls(for: .documentDirectory, in: .userDomainMask).first!
        let secureDir = documentsURL.appendingPathComponent(".secureStore", isDirectory: true)
        if !fileManager.fileExists(atPath: secureDir.path) {
            try? fileManager.createDirectory(at: secureDir, withIntermediateDirectories: true)
        }
        // Exclude from backups
        var resourceValues = URLResourceValues()
        resourceValues.isExcludedFromBackup = true
        var mutableURL = secureDir
        try? mutableURL.setResourceValues(resourceValues)
        return secureDir
    }()
    
    private init() {
        encoder.dateEncodingStrategy = .iso8601
        decoder.dateDecodingStrategy = .iso8601
    }
    
    // MARK: - Storage Keys
    
    enum StorageKey: String {
        case userCredentials = "user_credentials"
        case paymentTokens = "payment_tokens"
        case personalInfo = "personal_information"
    }
    
    // MARK: - Generic Save/Load
    
    func save<T: Encodable>(_ object: T, forKey key: StorageKey) throws {
        let jsonData = try encoder.encode(object)
        let encryptedData = try cryptoEngine.encrypt(data: jsonData)
        let fileURL = secureDirectoryURL.appendingPathComponent(key.rawValue)
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func load<T: Decodable>(_ type: T.Type, forKey key: StorageKey) throws -> T? {
        let fileURL = secureDirectoryURL.appendingPathComponent(key.rawValue)
        
        guard fileManager.fileExists(atPath: fileURL.path) else {
            return nil
        }
        
        let encryptedData = try Data(contentsOf: fileURL)
        let decryptedData = try cryptoEngine.decrypt(data: encryptedData)
        let object = try decoder.decode(T.self, from: decryptedData)
        return object
    }
    
    func delete(forKey key: StorageKey) throws {
        let fileURL = secureDirectoryURL.appendingPathComponent(key.rawValue)
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
        }
    }
    
    func deleteAll() throws {
        for key in [StorageKey.userCredentials, .paymentTokens, .personalInfo] {
            try delete(forKey: key)
        }
    }
    
