    }
    
    func loadCredentials() throws -> UserCredentials? {
        return try load(UserCredentials.self, forKey: .userCredentials)
    }
    
    func deleteCredentials() throws {
        try delete(forKey: .userCredentials)
    }
    
    // MARK: - Payment Tokens
    
