// MARK: - Password Hashing Utility

final class PasswordHasher {
    
    static func hash(password: String, salt: Data? = nil) throws -> (hash: String, salt: String) {
        let saltData: Data
        if let existingSalt = salt {
            saltData = existingSalt
        } else {
            var newSalt = Data(count: 32)
            let result = newSalt.withUnsafeMutableBytes { buffer in
                SecRandomCopyBytes(kSecRandomDefault, 32, buffer.baseAddress!)
            }
            guard result == errSecSuccess else {
                throw DataSecurityError.keyGenerationFailed
            }
            saltData = newSalt
        }
        
        guard let passwordData = password.data(using: .utf8) else {
            throw DataSecurityError.encodingFailed
        }
        
        let derivedKeyLength = 64
        var derivedKey = Data(count: derivedKeyLength)
        
        let status = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            saltData.withUnsafeBytes { saltBytes in
                passwordData.withUnsafeBytes { passwordBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress!.assumingMemoryBound(to: Int8.self),
                        passwordData.count,
                        saltBytes.baseAddress!.assumingMemoryBound(to: UInt8.self),
                        saltData.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                        100_000,
                        derivedKeyBytes.baseAddress!.assumingMemoryBound(to: UInt8.self),
                        derivedKeyLength
                    )
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.encryptionFailed(status: CCCryptorStatus(status))
        }
        
        return (
            hash: derivedKey.base64EncodedString(),
            salt: saltData.base64EncodedString()
        )
    }
    
    static func verify(password: String, hash: String, salt: String) throws -> Bool {
        guard let saltData = Data(base64Encoded: salt) else {
            throw DataSecurityError.invalidData
        }
        let result = try self.hash(password: password, salt: saltData)
        return result.hash == hash
    }
}

